#pragma once

#include <stdint.h>
#include <stdbool.h>
#include "dap_stream_transport.h"
#include "dap_stream_obfuscation.h"
#include "dap_chain_net.h"

/**
 * @file vpn_types.h
 * @brief Core type definitions for VPN client
 */

// Forward declarations
typedef struct vpn_sm vpn_sm_t;
typedef struct vpn_connection vpn_connection_t;
typedef struct vpn_config vpn_config_t;

/**
 * @brief VPN connection states
 */
typedef enum vpn_state {
    VPN_STATE_DISCONNECTED = 0,
    VPN_STATE_CONNECTING,
    VPN_STATE_VERIFYING,
    VPN_STATE_ROUTING_SETUP,
    VPN_STATE_CONNECTED,
    VPN_STATE_CONNECTION_LOST,
    VPN_STATE_RECONNECTING,
    VPN_STATE_DISCONNECTING,
    VPN_STATE_FAILED,
    VPN_STATE_SHUTDOWN,
    VPN_STATE_MAX
} vpn_state_t;

/**
 * @brief VPN state machine events
 */
typedef enum vpn_event {
    VPN_EVENT_USER_CONNECT = 0,
    VPN_EVENT_USER_DISCONNECT,
    VPN_EVENT_CONNECTION_SUCCESS,
    VPN_EVENT_CONNECTION_FAILED,
    VPN_EVENT_PROTOCOLS_PROBED,
    VPN_EVENT_VERIFICATION_SUCCESS,
    VPN_EVENT_VERIFICATION_FAILED,
    VPN_EVENT_ROUTING_COMPLETE,
    VPN_EVENT_ROUTING_FAILED,
    VPN_EVENT_KEEPALIVE_TIMEOUT,
    VPN_EVENT_RECONNECT_SUCCESS,
    VPN_EVENT_RECONNECT_FAILED,
    VPN_EVENT_SERVER_DISCONNECT,
    VPN_EVENT_SHUTDOWN,
    VPN_EVENT_MAX
} vpn_event_t;

/**
 * @brief VPN connection configuration
 */
struct vpn_config {
    char *server_host;
    uint16_t server_port;
    char *network_name;
    dap_stream_transport_type_t transport_type;
    dap_stream_obfuscation_level_t obfuscation_level;

    // Payment
    char *payment_tx_hash;
    char *payment_network;

    // Options
    bool manage_routing;
    bool manage_dns;
    bool auto_reconnect;

    // Timeouts
    uint32_t connection_timeout_ms;
    uint32_t keepalive_interval_ms;
};

