/**
 * @file vpn_errors.h
 * @brief VPN client error codes
 */

typedef enum vpn_error {
    VPN_OK = 0,

    // General errors
    VPN_ERROR = -1,
    VPN_ERROR_INVALID_PARAM = -2,
    VPN_ERROR_NO_MEMORY = -3,
    VPN_ERROR_NOT_INITIALIZED = -4,

    // Connection errors (-10 to -19)
    VPN_ERROR_CONNECTION_FAILED = -10,
    VPN_ERROR_CONNECTION_TIMEOUT = -11,
    VPN_ERROR_CONNECTION_LOST = -12,
    VPN_ERROR_HANDSHAKE_FAILED = -14,

    // Payment errors (-20 to -29)
    VPN_ERROR_PAYMENT_REQUIRED = -20,
    VPN_ERROR_PAYMENT_INVALID = -21,
    VPN_ERROR_RECEIPT_INVALID = -23,

    // Network errors (-30 to -39)
    VPN_ERROR_TUN_CREATE_FAILED = -30,
    VPN_ERROR_ROUTING_FAILED = -31,
    VPN_ERROR_DNS_FAILED = -32
} vpn_error_t;

const char* vpn_error_to_string(vpn_error_t error);

