state_machine_pseudocode.state_connecting_entry:
void state_connecting_entry(dap_chain_net_vpn_client_sm_t *sm) {
    log_info("[SM] Entering CONNECTING state");

    // Get all registered transport protocols
    dap_stream_transport_t **protocols = dap_stream_transport_registry_get_all(&protocol_count);

    if (sm->reconnect_policy.protocol_probe_enabled) {
        log_info("[SM] Starting parallel protocol probe for %d protocols", protocol_count);

        // Launch parallel probe
        dap_vpn_protocol_probe_params_t probe_params = {
            .server_address = sm->conn_params.server_address,
            .server_port = sm->conn_params.server_port,
            .protocols = protocols,
            .protocol_count = protocol_count,
            .timeout_ms = 10000,
            .on_protocol_established = sm_protocol_established_callback,
            .on_probe_complete = sm_probe_complete_callback,
            .user_data = sm
        };

        sm->protocol_probe = dap_vpn_protocol_probe_parallel_start(&probe_params);
    } else {
        // Legacy mode: single protocol
        log_info("[SM] Using single protocol (legacy mode)");
        dap_stream_t *stream = dap_stream_new(sm->conn_params.server_address, ...);
        sm->current_stream = stream;
    }
}

state_machine_pseudocode.sm_protocol_established_callback:
void sm_protocol_established_callback(dap_vpn_protocol_probe_t *probe, const char *protocol_name, dap_stream_t *stream, void *user_data) {
    dap_chain_net_vpn_client_sm_t *sm = user_data;
    log_info("[SM] Protocol %s established, handshake OK", protocol_name);

    // Add to temporary list
    dap_vpn_protocol_probe_add_established(probe, protocol_name, stream);

    // If this is first established protocol, trigger state transition
    if (dap_vpn_protocol_probe_get_established_count(probe) == 1) {
        log_info("[SM] First protocol ready, transitioning to VERIFYING_CONNECTIVITY");
        dap_chain_net_vpn_client_sm_process_event(sm, VPN_EVENT_PROTOCOL_READY);
    }
}

state_machine_pseudocode.state_verifying_entry:
void state_verifying_entry(dap_chain_net_vpn_client_sm_t *sm) {
    log_info("[SM] Entering VERIFYING_CONNECTIVITY state");

    // Get established protocols from probe
    dap_vpn_protocol_probe_result_t *results = dap_vpn_protocol_probe_get_results(sm->protocol_probe);

    log_info("[SM] Testing %d established protocols", results->established_count);

    // Start parallel verification
    for (int i = 0; i < results->established_count; i++) {
        dap_vpn_protocol_result_t *proto = &results->protocols[i];

        log_info("[SM] Verifying protocol %s...", proto->protocol_name);

        // Launch speed test in worker thread (non-blocking)
        dap_vpn_connectivity_test_params_t test_params = {
            .stream = proto->stream,
            .protocol_name = proto->protocol_name,
            .speed_test_url = "https://speedtest.cellframe.net/download?size=5mb",
            .latency_test_target = "speedtest.cellframe.net",
            .timeout_ms = 30000,
            .on_complete = sm_verification_complete_callback,
            .user_data = sm
        };

        dap_vpn_connectivity_test_start(&test_params);
    }

    // Set timeout for entire verification
    dap_timerfd_start(sm->verification_timeout_timer, 30000, sm_verification_timeout_callback, sm);
}

state_machine_pseudocode.sm_verification_complete_callback:
void sm_verification_complete_callback(dap_vpn_connectivity_test_t *test, dap_vpn_connectivity_result_t *result, void *user_data) {
    dap_chain_net_vpn_client_sm_t *sm = user_data;

    log_info("[SM] Protocol %s verification complete: throughput=%.2f Mbps, latency=%d ms, score=%.3f",
             result->protocol_name, result->throughput_mbps, result->latency_ms, result->score);

    // Store result
    dap_vpn_protocol_probe_update_result(sm->protocol_probe, result);

    // Check if all verifications complete
    if (dap_vpn_protocol_probe_all_verified(sm->protocol_probe)) {
        log_info("[SM] All protocols verified, selecting best ones");

        // Select best N protocols
        dap_vpn_protocol_probe_result_t *sorted = dap_vpn_protocol_probe_get_sorted_by_score(sm->protocol_probe);

        int desired_count = sm->conn_params.multi_uplink_count;
        int selected_count = min(desired_count, sorted->verified_ok_count);

        if (selected_count == 0) {
            log_error("[SM] No protocols passed verification!");
            dap_chain_net_vpn_client_sm_process_event(sm, VPN_EVENT_CONNECTION_FAILED);
            return;
        }

        log_info("[SM] Selected %d best protocols for uplink pool", selected_count);

        // Add to uplink pool
        for (int i = 0; i < selected_count; i++) {
            dap_vpn_uplink_add(sm->uplink_pool, sorted->protocols[i].stream, sorted->protocols[i].protocol_name, sorted->protocols[i].score);
        }

        // Close non-selected protocols
        for (int i = selected_count; i < sorted->established_count; i++) {
            log_info("[SM] Closing non-selected protocol %s", sorted->protocols[i].protocol_name);
            dap_stream_close(sorted->protocols[i].stream);
        }

        // Transition to CONNECTED
        dap_chain_net_vpn_client_sm_process_event(sm, VPN_EVENT_CONNECTED);
    }
}
